void i2c_int(void)
{
	SIM->SCGC |=	(1<<17);									/*	turn	on	clock	to	I2C1*/
  SIM->PINSEL |= (1<<5);
	I2C0->C1 |= 0;
	I2C0->S	=	0x02;																/*	Clear	interrupt	flag	*/
  I2C0->F	=	0X0F;//0x1C;													/*	set	clock	to	97.09KHz	@13.981MHz	bus	clock	*/
  I2C0->C1	=	0x80;		
}

void i2c_start(void){
	int retry = 1000; 
    while (I2C0->S & 0x20) {    /* wait until bus is available */
        if (--retry <= 0)
        Delay(100);
    }
    /* send start */
    I2C0->C1 |= 0x10;    /* Tx on */
    I2C0->C1 |= 0x20;   

}

void i2c_start1(void){
	int retry = 1000; 
    while (I2C0->S & 0x20) {    /* wait until bus is available */
        if (--retry <= 0){
					break;}
				}
    /* send start */
    I2C0->C1 |= 0x10;    /* Tx on */
    I2C0->C1 |= 0x20;   

}

void i2c_add(char address, char RW) {
	    int retry = 2000;
	I2C0->D = (address << 1) | RW;         // Send the slave address with read/write bit

    //while (!(I2C0->S & 0x02));          // Wait for transfer complete
	while (!(I2C0->S & 0x02)) {
        if (--retry <= 0) {
            break; // timeout
        }
    }
    I2C0->S |= (1 << 1);               // Clear interrupt flag
    if (I2C0->S & 0x10) {             // Check for arbitration lost
        I2C0->S |= 0x10;             // Clear ARBL
    }
    if (I2C0->S & 0x01) {          // Check for NACK from slave
        // Handle NACK if needed
    }
}


void i2c_data(char data) {
		int retry = 200; 
    I2C0->D = data;  	// Send data
    while (I2C0->S & 0x20) {    /* wait until bus is available */
        if (--retry <= 0){
					break;}
				}
   // while (!(I2C0->S & 0x02));     // Wait for transfer complete
    I2C0->S |= 0x02;              // Clear interrupt flag
    if (I2C0->S & 0x01) {         // Check for NACK from slave

    }
}

void i2c_stop(void){
I2C0->C1 &= ~0x30;
}


void i2c_write(char address,char data[]){
uint16_t i=0;
i2c_start1();
i2c_add(address,0); 
	while(data[i]){
			i2c_data(data[i]);
			i++;
		}
	i2c_stop();
}

void oled_cmd_1byte(char data){
  i2c_int();
	i2c_start1();
	i2c_add(0x3C,0); //0x78 is the primary address
	i2c_data(0x00); // Control function for a command
	i2c_data(data);

	i2c_stop();
}
void oled_cmd_2byte(char data[]){
	int i = 0;
	i2c_int();
	i2c_start1();
	i2c_add(0x3C,0); //0x78 is the primary address
	i2c_data(0x00); // Control function for a command
	for (i=0;i<2;i++)
	{
		i2c_data(data[i]);
	}
	i2c_stop();
}

