void oled_data(char data)
{
	i2c_start1();
	i2c_add(0x3C,0); //0x78 is the primary address
	i2c_data(0x40); // Control function for a data
	i2c_data(data);
	i2c_stop();
}

void oled_pos(char Ypos, char Xpos){
	oled_cmd_1byte(0x00 + (0x0F & Xpos));
	oled_cmd_1byte(0x10 + (0x0F & (Xpos>>4)));
	oled_cmd_1byte(0xB0  + Ypos);
}
void oled_blank(void) {
    int i, j;
    oled_pos(0, 0); // Set initial position
	for (i = 0; i < 8; i++) { // Iterate through all 8 pages
       oled_pos(i, 0); // Set the column to 0 for each page
        for (j = 0; j < 129; j++) { // Iterate through all 128 columns
            oled_data(0x00); // Send 0x00 to turn off all pixels
        }
    }
}

void oled_clear_area(uint8_t page, uint8_t col, uint8_t width)
{
	uint8_t p=0,j=0;
    for(p = 0; p < VER_PAGE_REQ; p++)
    {
        oled_cmd_1byte(0xB0 + page + p);
        oled_cmd_1byte(0x00 + (col & 0x0F));
        oled_cmd_1byte(0x10 + ((col >> 4) & 0x0F));

        i2c_start1();
        i2c_add(0x3C, 0);
        i2c_data(0x40);

        for(j = 0; j < width; j++)
            i2c_data(0x00);

        i2c_stop();
    }
}


void Display_control_On(void) {
	oled_cmd_1byte(0x8D);  
	oled_cmd_1byte(0x14);  
	oled_cmd_1byte(0xAF);  
}
void Display_control_Off(void) {
	oled_cmd_1byte(0x8D);  
	oled_cmd_1byte(0x10);
	oled_cmd_1byte(0xAE);  
}

void print_char(char ch, char x_cord, char y_cord)
{
      char j=0,i=0;
	int array_index;
  char index = ch-32;
  int char_start_in_array  = index * NO_0F_BYTES_CHAR + 1;//no of bytes per row64
  if (ch < 32 || ch > 127) return;

  for ( j = x_cord; j < x_cord + HOR_COL_REQ ; j++)//horizontal 21
  {
    for ( i = y_cord; i < y_cord + VER_PAGE_REQ; i++)//vertical 3
    {
      oled_pos(i,j);
      array_index = char_start_in_array + (j - x_cord) * VER_PAGE_REQ + (i - y_cord);
                  oled_data(ASCII_16[array_index]);
			 //Delay(2);
			if (array_index < sizeof(ASCII_16))
                oled_data(ASCII_16[array_index]);
            else
                oled_data(0x00);  // Safe fallback
    }
  }
}




void draw_icon(const uint8_t *icon, char x, char y_page, char width, char pages) {
	char page=0,col=0;
    for ( page = 0; page < pages; page++) {
        oled_pos(y_page + page, x);  // Set position to (x, page)
        for ( col = 0; col < width; col++) {
            oled_data(icon[page * width + col]);  // Send each column byte
        }
    }
}




