void print_string(char *s, char x, char y, int length)
{
    int i;
    int x_pos = x;  // running horizontal position

    for(i = 0; i < length; i++)
    {
        char ch = s[i];

        // Print the character at current position
        print_char(ch, x_pos, y);

        // Update x_pos for next character
        if(ch == 'W' || ch == 'w'||ch=='M' || ch=='m') {
            x_pos += HOR_COL_REQ ;  // extra spacing after W
        } else {
            x_pos += HOR_COL_REQ - 7;  // normal spacing
        }
    }
}

